async function solveAndStream(problem) {
  // 1. Start async solve
  const response = await fetch("/api/v2/solve/async", {
    method: "POST",
    headers: {
      "Authorization": "Bearer oklive...",
      "Content-Type": "application/json",
    },
    body: JSON.stringify(problem),
  });
  const { taskid, wsurl } = await response.json();

  // 2. Connect WebSocket
  const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
  const ws = new WebSocket(${protocol}//${window.location.host}${wsurl});

  // 3. Handle messages
  ws.onmessage = (event) => {
    const msg = JSON.parse(event.data);

    switch (msg.type) {
      case "status":
        console.log("Initial status:", msg.status);
        break;

      case "progress":
        const pct = (msg.progress  100).toFixed(0);
        console.log(Progress: ${pct}% | Objective: ${msg.objectivevalue});
        // Update your UI progress bar
        updateProgressBar(msg.progress);
        updateObjectiveDisplay(msg.objectivevalue, msg.gap);
        break;

      case "completed":
        console.log("Solution:", msg.result.solution);
        console.log("Objective:", msg.result.objectivevalue);
        displayResults(msg.result);
        ws.close();
        break;

      case "failed":
        console.error("Solve failed:", msg.error);
        displayError(msg.error);
        ws.close();
        break;
    }
  };

  // 4. Send keepalive ping every 30 seconds
  const pingInterval = setInterval(() => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send("ping");
    }
  }, 30000);

  ws.onclose = () => {
    clearInterval(pingInterval);
    console.log("WebSocket closed");
  };

  ws.onerror = (error) => {
    console.error("WebSocket error:", error);
  };
}
